{
  "terms": [
    {
      "term": "Resistance",
      "simpleDefinition": "The total opposition that a circuit or component offers to the flow of electric current, measured in Ohms (Ω).",
      "anchor": "Think of it as the 'electrical friction' that slows down the flow of electrons in a wire.",
      "misconception": "Believing resistance only exists in specific components like heaters; in reality, every wire and connection has some resistance."
    },
    {
      "term": "Resistivity",
      "simpleDefinition": "The inherent property of a material that determines how strongly it opposes current, regardless of its shape.",
      "anchor": "The 'DNA' of a material; copper has low resistivity, while rubber has extremely high resistivity.",
      "misconception": "Confusing resistivity with resistance; resistivity is about the material type, while resistance is about the specific object's size and shape."
    },
    {
      "term": "Voltage Drop",
      "simpleDefinition": "The reduction in electrical pressure (voltage) as current passes through a resistance in a circuit.",
      "anchor": "Like the drop in water pressure at the end of a very long garden hose.",
      "misconception": "Thinking voltage stays exactly the same from the consumer unit to the furthest socket in a house."
    },
    {
      "term": "Conductor",
      "simpleDefinition": "A material, such as copper or aluminum, that has low resistivity and allows electricity to flow easily.",
      "anchor": "The metal core inside an electrical cable.",
      "misconception": "Assuming all metal conductors are the same; different metals have different resistivity levels."
    }
  ],
  "anchorPhrases": [
    "Opposition to current flow",
    "Inherent material property",
    "Loss of electrical pressure",
    "Resistance of a unit cube",
    "Voltage loss across a conductor"
  ],
  "misconceptionTargets": [
    "Resistance is not just in 'resistors' but in every part of the circuit path.",
    "Resistivity is a constant for the material, while resistance changes with length and thickness.",
    "Voltage drop is a natural consequence of current flowing through any resistance, not just a fault."
  ]
}

