        {
          "questionText": "In the chain of causality, what is the result of combining a material's resistivity with its physical dimensions?",
          "answerGuidance": [
            "Resistance"
          ],
          "hint": "This is the total opposition of that specific conductor.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        },
        {
          "questionText": "What practical outcome occurs when current flows through the total resistance of a system?",
          "answerGuidance": [
            "Voltage drop"
          ],
          "hint": "This is the loss of electrical pressure at the end of the line.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        },
        {
          "questionText": "What is the primary goal of an electrician regarding voltage at the point of use?",
          "answerGuidance": [
            "Ensure enough voltage"
          ],
          "hint": "The equipment needs a certain amount of electrical pressure to work.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        }
      ],
      "deeperQuestionText": "How does the initial choice of conductor material (resistivity) directly affect the performance of a load at the end of a circuit?",
      "deeperAnswerGuidance": [
        "Material resistivity determines total resistance",
        "Resistance causes voltage drop",
        "High resistivity leads to higher voltage loss",
        "Insufficient voltage at the point of use affects performance"
      ],
      "deeperSourceTeachingPointIds": [
        "TP1",
        "TP2"
      ],
      "hint": "Trace the path from the material property to the final electrical pressure available."
    }
  ]
}

